    void M()
    {
        Span<int> a;
        unsafe { a = stackalloc int[5]; }
    }
    ```

*   Or provide an initializer so the memory is fully initialized:

    ```
    [SkipLocalsInit]
    void M()
    {
        Span<int> a = stackalloc int[5] { 0, 0, 0, 0, 0 };
    }
    ```

